import{c as s,Q as i,j as e,m as t}from"./chunks/framework.B46-fMMG.js";const n="/librislog/screenshots/admin-users.png",r="/librislog/screenshots/admin-backup.png",g=JSON.parse('{"title":"Administration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/administration.md","filePath":"guide/using-librislog/administration.md","lastUpdated":1780244094000}'),l={name:"guide/using-librislog/administration.md"};function o(p,a,h,d,k,c){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="administration" tabindex="-1">Administration <a class="header-anchor" href="#administration" aria-label="Permalink to &quot;Administration&quot;">​</a></h1><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>The administration page is available only to users with the <strong>admin</strong> role. Regular users cannot access it.</p></div><p><img src="'+n+'" alt="Users tab" loading="lazy"></p><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><h3 id="creating-a-user" tabindex="-1">Creating a User <a class="header-anchor" href="#creating-a-user" aria-label="Permalink to &quot;Creating a User&quot;">​</a></h3><p>Admins can create new user accounts with either the <code>user</code> or <code>admin</code> role. The password must meet the complexity requirements displayed in the form.</p><h3 id="editing-a-user" tabindex="-1">Editing a User <a class="header-anchor" href="#editing-a-user" aria-label="Permalink to &quot;Editing a User&quot;">​</a></h3><p>Click &quot;Edit&quot; next to a user to change their name, email, password, or role. You cannot change your own admin role to prevent accidental lockout.</p><h3 id="deleting-a-user" tabindex="-1">Deleting a User <a class="header-anchor" href="#deleting-a-user" aria-label="Permalink to &quot;Deleting a User&quot;">​</a></h3><p>Click &quot;Delete&quot; to remove a user account. You cannot delete your own account from this page — use the <strong>Profile → Danger Zone</strong> instead.</p><h2 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h2><p><img src="'+r+`" alt="Backup and Restore tab" loading="lazy"></p><h3 id="creating-a-backup" tabindex="-1">Creating a Backup <a class="header-anchor" href="#creating-a-backup" aria-label="Permalink to &quot;Creating a Backup&quot;">​</a></h3><p>Downloads a ZIP archive containing the SQLite database, cover images, and import temp files. This is a complete snapshot of your library, users, and settings.</p><h3 id="restoring-a-backup" tabindex="-1">Restoring a Backup <a class="header-anchor" href="#restoring-a-backup" aria-label="Permalink to &quot;Restoring a Backup&quot;">​</a></h3><p>Upload a previously downloaded <code>.zip</code> backup file to restore the database. The app validates the backup before applying it. Backups from older versions are automatically migrated to the current schema on restore.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Restoring overwrites all current data. Create a fresh backup first if you want to preserve your current library.</p></div><h3 id="automating-backups" tabindex="-1">Automating Backups <a class="header-anchor" href="#automating-backups" aria-label="Permalink to &quot;Automating Backups&quot;">​</a></h3><p>The backup endpoint is accessible via the REST API, making it easy to automate with cron (or any scheduler).</p><p>First, <a href="/librislog/api/setup.html#3-create-an-api-key">create an API key</a> with the admin user. Then use it in a cron script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Save as /etc/cron.daily/librislog-backup or add to crontab</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;lsk_your-key-here&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://localhost:8000/api/admin/backup&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/var/backups/librislog&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;X-API-Key: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$API_KEY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/librislog-$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%F).zip&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Keep only the last 30 backups</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;librislog-*.zip&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mtime</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +30</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -delete</span></span></code></pre></div><p>Crontab entry (daily at 3am):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0 3 * * * /path/to/backup-script.sh</span></span></code></pre></div><p>The API returns a ZIP archive containing the SQLite database, cover images, and import temp files. No separate database dump step is needed.</p><h2 id="background-maintenance" tabindex="-1">Background Maintenance <a class="header-anchor" href="#background-maintenance" aria-label="Permalink to &quot;Background Maintenance&quot;">​</a></h2><p>A periodic maintenance task runs automatically every hour. It performs:</p><ul><li><strong>Cover cache cleanup</strong> — Removes orphaned cover images from disk that are no longer referenced by any book. Files modified within the last 60 minutes are preserved to avoid deleting covers that were just uploaded but not yet linked to a book entry.</li></ul>`,27)])])}const m=s(l,[["render",o]]);export{g as __pageData,m as default};
